import type { FC, PropsWithChildren } from 'react';
import React from 'react';
/**
 * @file size.ts
 * 单独提供 size context 的原因是 form 组件会重新设置 ctx.size 的值
 */
import { createContext, useContext } from 'use-context-selector';
import type { DefaultSizeType } from '../util';

// 在使用 InputGroup 的场景中设置 InputGroup 内的元素大小
export const InputGroupSizeContext = createContext<DefaultSizeType | undefined>(undefined);

export const InputGroupSizeContextProvider: FC<PropsWithChildren<{ size?: DefaultSizeType }>> = ({
  size,
  children,
}) => {
  const origSize = useContext(InputGroupSizeContext);
  return <InputGroupSizeContext.Provider value={size ?? origSize}>{children}</InputGroupSizeContext.Provider>;
};
